import React, { useState, useRef } from 'react';
import { Link } from 'react-router-dom';
import { useSelector } from 'react-redux';
import { Search, User, Heart, ShoppingCart } from 'lucide-react';

const Navbar = () => {
  const [isSearchActive, setIsSearchActive] = useState(false);
  const searchInputRef = useRef(null);

  // Getting cart count dynamically from your Redux store
  const cartItems = useSelector((state) => state.cart?.items || []);
  const cartCount = cartItems.reduce((total, item) => total + item.quantity, 0);

  const handleMouseLeave = () => {
    // Keep search open if the user is actively typing/focused inside it
    if (document.activeElement !== searchInputRef.current) {
      setIsSearchActive(false);
    }
  };

  return (
    <header className="w-full bg-white shadow-sm sticky top-0 z-50">
      {/* Top Promotional Banner */}
      <div className="w-full bg-gray-50 py-1.5 border-b border-gray-200">
        <p className="text-center text-xs md:text-sm text-gray-700">
          Free Shipping on Orders Above ₹10,000 | <span className="text-orange-500 font-semibold">Use Code: VIDEM10</span>
        </p>
      </div>

      {/* Main Navbar Elements */}
      <div className="container mx-auto px-4 py-4">
        <div className="flex items-center justify-between gap-4 md:gap-8">

          {/* Logo */}
          <Link to="/" className="flex-shrink-0">
            <h1 className="text-2xl md:text-3xl font-bold tracking-tight">
              <span className="text-gray-900">Videm's</span> <span className="text-orange-500">Gallery</span>
            </h1>
          </Link>

          {/* Expanding Search Bar */}
          <div className="flex-1 flex justify-end lg:justify-center relative h-10 z-20">
            <div
              className={`absolute right-0 flex items-center transition-all duration-300 ease-in-out ${isSearchActive ? 'w-full max-w-xl' : 'w-10'
                }`}
              onMouseEnter={() => setIsSearchActive(true)}
              onMouseLeave={handleMouseLeave}
            >
              <input
                ref={searchInputRef}
                type="text"
                placeholder="Search for furniture and more..."
                className={`h-10 bg-gray-100 text-sm text-gray-800 outline-none transition-all duration-300 ease-in-out ${isSearchActive
                    ? 'w-full opacity-100 pl-4 rounded-l-md border border-r-0 border-gray-200 focus:border-orange-500 focus:ring-1 focus:ring-orange-500'
                    : 'w-0 opacity-0 px-0 border-none'
                  }`}
                onFocus={() => setIsSearchActive(true)}
                onBlur={() => setIsSearchActive(false)}
              />
              <button
                className={`h-10 w-10 flex items-center justify-center bg-orange-500 hover:bg-orange-600 text-white transition-all duration-300 ${isSearchActive ? 'rounded-r-md' : 'rounded-md shadow-sm hover:scale-105'
                  }`}
                aria-label="Search"
              >
                <Search size={18} />
              </button>
            </div>
          </div>

          {/* Action Icons (Hidden on mobile, since MobileBottomNav handles them) */}
          <div className="hidden md:flex items-center space-x-6 lg:space-x-8 flex-shrink-0">
            <Link to="/profile" className="flex flex-col items-center gap-1 text-gray-700 hover:text-orange-500 transition-colors">
              <User size={24} />
              <span className="text-[10px] font-bold tracking-wider uppercase">Profile</span>
            </Link>

            <Link to="/wishlist" className="flex flex-col items-center gap-1 text-gray-700 hover:text-orange-500 transition-colors">
              <Heart size={24} />
              <span className="text-[10px] font-bold tracking-wider uppercase">Wishlist</span>
            </Link>

            <Link to="/cart" className="flex flex-col items-center gap-1 text-gray-700 hover:text-orange-500 transition-colors relative group">
              <div className="relative">
                <ShoppingCart size={24} className="group-hover:scale-110 transition-transform" />
                {cartCount > 0 && (
                  <span className="absolute -top-2 -right-2 bg-orange-500 text-white text-[10px] font-bold h-5 w-5 rounded-full flex items-center justify-center border border-white">
                    {cartCount > 99 ? '99+' : cartCount}
                  </span>
                )}
              </div>
              <span className="text-[10px] font-bold tracking-wider uppercase">Cart</span>
            </Link>
          </div>
        </div>
      </div>

      {/* Bottom Navigation Links (Hidden on mobile) */}
      <div className="hidden md:block w-full border-t border-gray-100 bg-white">
        <div className="container mx-auto px-4 py-3">
          <ul className="flex items-center justify-center space-x-12">
            {['LIVING ROOM', 'BEDROOM', 'DINING', 'STUDY'].map((category) => (
              <li key={category}>
                <Link
                  to={`/products?category=${category.toLowerCase().replace(' ', '-')}`}
                  className="text-sm font-bold text-gray-800 hover:text-orange-500 tracking-wide transition-colors"
                >
                  {category}
                </Link>
              </li>
            ))}
          </ul>
        </div>
      </div>
    </header>
  );
};

export default Navbar;
